fn build_workspace_window_path(request: &OpenWorkspaceWindowRequest) -> String {
    let mut query = vec![format!(
        "workspace={}",
        urlencoding::encode(&request.workspace)
    )];

    if let Some(case_id) = &request.case_id {
        query.push(format!("caseId={}", urlencoding::encode(case_id)));
    }

    if let Some(module) = &request.module {
        query.push(format!("module={}", urlencoding::encode(module)));
    }

    format!("/?{}", query.join("&"))
}

