#[tauri::command]
fn open_workspace_window(
    app: tauri::AppHandle,
    request: OpenWorkspaceWindowRequest,
) -> Result<(), String> {
    if let Some(existing_window) = app.get_webview_window(&request.label) {
        let _ = existing_window.unminimize();
        let _ = existing_window.show();
        existing_window
            .set_focus()
            .map_err(|error| error.to_string())?;
        return Ok(());
    }

    let window = WebviewWindowBuilder::new(
        &app,
        &request.label,
        WebviewUrl::App(build_workspace_window_path(&request).into()),
    )
    .title(
        request
            .title
            .unwrap_or_else(|| "TlantiCAD Studio".to_string()),
    )
    .inner_size(1600.0, 960.0)
    .min_inner_size(960.0, 620.0)
    .resizable(true)
    .center()
    .build()
    .map_err(|error| error.to_string())?;

    let _ = window.show();
    let _ = window.set_focus();

    Ok(())
}

